def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    fraction = ((ratio - a) ** 6) / (a * b * 1.1 + 1)
                    trig = np.sin(ratio * b / (a + 2)) + np.cos(ratio * a / (b + 1))
                    priority += fraction * trig * np.exp(-0.1 * (a + b))
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7
            for c in range(1, 5):
                priority += np.tanh(ratio * c * i / (c + 1)) * (c + 0.5)
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.cos(ratio * p * 0.75) / (q + 0.7)
                    priority += np.tanh(val) * 1.4
            priority += np.log(ratio + 0.5) * 12 - np.tanh(ratio - 4) * 2.5
            for t in range(1,6):
                priority += np.sin(ratio * t * i / (t + 2)) * 0.8
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.0) * np.cos(r * ratio * 0.9)
            priority = s * np.cos(8 * ratio) - np.log(ratio) * 7 + np.tanh(3.5 * (4 - ratio)) * 2
            for m in range(1, 6):
                priority += np.sin(m * i * ratio * 0.9) * ((ratio - 1.9) ** m) / (m + 0.5)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1.0)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.0
            priority = s + penalty + np.exp(-1.3 / (ratio + 0.1))
            for k in range(1, 7):
                priority += np.sin(k * ratio * i) * ((ratio - 1) ** k) / (k + 1)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 5)
            if (i + int(item * 2)) % 5 == 0:
                priority = s * np.log1p(bin_cap + 4) * 1.6
            else:
                priority = s / (np.sqrt(bin_cap + 2.5) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
            if bin_cap < item * 0.8:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.1) % 3 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 2.5) * 2
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.0)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.6) % 4 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 3) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
